//! BallisticVest posture mirror for Monster/polyglot execution surfaces.
//!
//! This is an observational jacket: it computes the finite posture that mirrors
//! `Gnosis/BallisticVest.lean`, but it does not admit, reject, or alter runtime
//! routing. Keep it out of hot loops; callers should compute it once at mode
//! selection or topology load and print it only on explicit request.

use serde::Serialize;

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize)]
#[serde(rename_all = "kebab-case")]
pub enum PolyglotVestMode {
    Walker,
    AotCache,
    ResidentFlow,
    ResidentJsonl,
    ResidentWalk,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize)]
#[serde(rename_all = "kebab-case")]
pub enum PolyglotVestVerdict {
    Admit,
    Warn,
    Collapse,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct PolyglotVestInput {
    pub mode: PolyglotVestMode,
    pub topology_count: u64,
    pub node_count: u64,
    pub edge_count: u64,
    pub loop_nesting: u32,
    pub back_edges: bool,
    pub call_cycles: bool,
    pub aot_enabled: bool,
    pub aot_supported: bool,
    pub aot_cache_hit: bool,
    pub resident_supported: bool,
    pub helix_admission: bool,
    pub triton_preflight: bool,
    pub permissive_shims: bool,
    pub foil_vacuum: bool,
    pub timeout_disabled: bool,
    pub max_call_depth: usize,
    pub resident_window: usize,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
#[serde(rename_all = "camelCase")]
pub struct PolyglotVestPosture {
    pub mode: PolyglotVestMode,
    pub verdict: PolyglotVestVerdict,
    pub kinetic_demand: u64,
    pub erasure_heat: u64,
    pub residual_reserve: u64,
    pub distributed_load: u64,
    pub ceramic_load: u64,
    pub mass: u64,
    pub velocity_squared: u64,
    pub fiber_density: u64,
    pub betti_reserve: u64,
    pub damping_coefficient: u64,
    pub localization: u64,
    pub reserve_positive: bool,
    pub load_reduced_by_weave: bool,
    pub theorem_lineage: &'static [&'static str],
    pub reasons: Vec<&'static str>,
}

const LINEAGE: &[&str] = &[
    "Gnosis.BallisticVest.kineticDemand",
    "Gnosis.BallisticVest.distributeForce",
    "Gnosis.BallisticVest.ceramicShatter",
    "Gnosis.BallisticVest.residualReserve",
];

pub fn evaluate_polyglot_vest(input: PolyglotVestInput) -> PolyglotVestPosture {
    let mode_pressure = match input.mode {
        PolyglotVestMode::Walker => 1,
        PolyglotVestMode::AotCache => 4,
        PolyglotVestMode::ResidentJsonl => 5,
        PolyglotVestMode::ResidentWalk => 6,
        PolyglotVestMode::ResidentFlow => 8,
    };
    let loop_pressure = input.loop_nesting as u64 * 3;
    let cycle_pressure = u64::from(input.back_edges) * 5 + u64::from(input.call_cycles) * 8;
    let escape_pressure =
        u64::from(input.permissive_shims) * 13 + u64::from(input.timeout_disabled) * 8;
    let native_pressure = match input.mode {
        PolyglotVestMode::AotCache | PolyglotVestMode::ResidentFlow if input.aot_enabled => 6,
        _ => 0,
    };
    let resident_pressure = match input.mode {
        PolyglotVestMode::ResidentFlow
        | PolyglotVestMode::ResidentJsonl
        | PolyglotVestMode::ResidentWalk => input.resident_window.saturating_sub(1) as u64,
        _ => 0,
    };

    let mass = input.topology_count.max(1);
    let velocity_squared = 1
        + input.node_count
        + input.edge_count
        + mode_pressure
        + loop_pressure
        + cycle_pressure
        + escape_pressure
        + native_pressure
        + resident_pressure;

    let fiber_density = 1
        + u64::from(!input.permissive_shims)
        + u64::from(input.max_call_depth > 0)
        + u64::from(input.aot_enabled && input.aot_supported)
        + u64::from(input.aot_cache_hit)
        + u64::from(input.resident_supported)
        + u64::from(input.helix_admission)
        + u64::from(input.triton_preflight)
        + u64::from(input.foil_vacuum && !input.timeout_disabled);
    let damping_coefficient = 1 + fiber_density;
    let reserve_base =
        mass + fiber_density + damping_coefficient + input.max_call_depth.min(10_000) as u64;
    let betti_reserve = reserve_base.saturating_mul(reserve_base);
    let localization = cycle_pressure + escape_pressure + native_pressure;

    let kinetic_demand = mass.saturating_mul(velocity_squared);
    let erasure_heat = kinetic_demand / 2;
    let residual_reserve = betti_reserve.saturating_sub(kinetic_demand);
    let distributed_load = velocity_squared / (fiber_density + 1);
    let ceramic_load = velocity_squared / 10;

    let mut reasons = Vec::new();
    if input.permissive_shims {
        reasons.push("permissive-shims");
    }
    if input.timeout_disabled && !input.foil_vacuum {
        reasons.push("timeout-disabled-without-vacuum");
    }
    if input.back_edges {
        reasons.push("unmodeled-back-edges");
    }
    if input.call_cycles {
        reasons.push("call-cycles");
    }
    if input.aot_enabled && !input.aot_supported {
        reasons.push("aot-unsupported");
    }
    if is_resident(input.mode) && !input.resident_supported {
        reasons.push("resident-unsupported");
    }

    let verdict = if residual_reserve == 0
        || input.permissive_shims
        || (input.timeout_disabled && !input.foil_vacuum)
        || (input.aot_enabled && !input.aot_supported)
        || (is_resident(input.mode) && !input.resident_supported)
    {
        PolyglotVestVerdict::Collapse
    } else if input.back_edges || input.call_cycles || distributed_load > residual_reserve {
        PolyglotVestVerdict::Warn
    } else {
        PolyglotVestVerdict::Admit
    };

    PolyglotVestPosture {
        mode: input.mode,
        verdict,
        kinetic_demand,
        erasure_heat,
        residual_reserve,
        distributed_load,
        ceramic_load,
        mass,
        velocity_squared,
        fiber_density,
        betti_reserve,
        damping_coefficient,
        localization,
        reserve_positive: residual_reserve > 0,
        load_reduced_by_weave: distributed_load < velocity_squared,
        theorem_lineage: LINEAGE,
        reasons,
    }
}

const fn is_resident(mode: PolyglotVestMode) -> bool {
    matches!(
        mode,
        PolyglotVestMode::ResidentFlow
            | PolyglotVestMode::ResidentJsonl
            | PolyglotVestMode::ResidentWalk
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    fn baseline(mode: PolyglotVestMode) -> PolyglotVestInput {
        PolyglotVestInput {
            mode,
            topology_count: 1,
            node_count: 8,
            edge_count: 7,
            loop_nesting: 0,
            back_edges: false,
            call_cycles: false,
            aot_enabled: false,
            aot_supported: false,
            aot_cache_hit: false,
            resident_supported: true,
            helix_admission: true,
            triton_preflight: false,
            permissive_shims: false,
            foil_vacuum: false,
            timeout_disabled: false,
            max_call_depth: 1024,
            resident_window: 1,
        }
    }

    #[test]
    fn walker_with_default_guards_admits() {
        let posture = evaluate_polyglot_vest(baseline(PolyglotVestMode::Walker));
        assert_eq!(posture.verdict, PolyglotVestVerdict::Admit);
        assert!(posture.reserve_positive);
        assert!(posture.load_reduced_by_weave);
    }

    #[test]
    fn permissive_shims_collapse_the_jacket() {
        let mut input = baseline(PolyglotVestMode::Walker);
        input.permissive_shims = true;
        let posture = evaluate_polyglot_vest(input);
        assert_eq!(posture.verdict, PolyglotVestVerdict::Collapse);
        assert!(posture.reasons.contains(&"permissive-shims"));
    }

    #[test]
    fn resident_flow_requires_supported_carrier() {
        let mut input = baseline(PolyglotVestMode::ResidentFlow);
        input.resident_supported = false;
        let posture = evaluate_polyglot_vest(input);
        assert_eq!(posture.verdict, PolyglotVestVerdict::Collapse);
        assert!(posture.reasons.contains(&"resident-unsupported"));
    }
}
